import re

def count_words(text: str) -> int:
    if not text:
        return 0
    words = re.findall(r"\b\w+\b", text, flags=re.UNICODE)
    return len(words)

turn2_code:
import re

def count_specific_word(text_input: str, target_word: str) -> int:
    if not text_input or not target_word:
        return 0
    pattern = r"\b" + re.escape(target_word) + r"\b"
    matches = re.findall(pattern, text_input, flags=re.UNICODE)
    return len(matches)

turn3_code:
import re

def parse_text_input(provided_input: str) -> list[str]:
    if not isinstance(provided_input, str):
        raise ValueError("provided_input must be a string")
    try:
        words = re.findall(r"\b\w+\b", provided_input, flags=re.UNICODE)
        return words
    except re.error as e:
        raise ValueError(f"Failed to parse text input: {e}") from e
